import React from 'react';
import { Link } from 'react-router-dom';

function Navbar() {
  return (
    <header className="bg-white shadow-md">
      <nav className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
        <Link to="/" className="text-2xl font-bold text-blue-600">HEALink</Link>
        <div className="space-x-4">
          <Link to="/about" className="text-gray-600 hover:text-blue-600">About</Link>
          <Link to="/login"><button className="text-blue-600 border border-blue-600 px-4 py-1.5 rounded-lg">Login</button></Link>
          <Link to="/register"><button className="bg-red-500 text-white px-4 py-1.5 rounded-lg">Register</button></Link>
        </div>
      </nav>
    </header>
  );
}

export default Navbar;
